#include<bits/stdc++.h>
using namespace std;
long long dp[2010][2010],f[2010][2010];
struct node
{
	int a,c,x;
	bool operator<(const node&b)const
	{
		return x<b.x;
	}
}a[2010];
int main()
{
	int n,m,k;
	scanf("%d%d%d",&n,&m,&k);
	for(int i=1;i<=n;i++)
	{
		scanf("%d%d%d",&a[i].a,&a[i].c,&a[i].x);
	}
	sort(a+1,a+1+n);
	for(int i=n;i>=1;i--)
	{
		memcpy(dp[i],dp[i+1],sizeof(dp[i+1]));
		for(int j=a[i].c;j<=m;j++)
		{
			dp[i][j]=max(dp[i][j],dp[i+1][j-a[i].c]+a[i].a);
		}
	}
	long long ans=0;
	for(int i=n;i>=1;i--)
	{
		for(int j=0;j<=k;j++)
		{
			f[i][j]=f[i+1][j];
			long long tmp=min(a[i].c,j/a[i].x);
			long long v=j-tmp*a[i].x;
			if(tmp==a[i].c)
			{
				f[i][j]=max(f[i][j],f[i+1][v]+a[i].a);
			}
			else
			{
				f[i][j]=max(f[i][j],dp[i+1][m-(a[i].c-tmp)]+a[i].a);
			}
			ans=max(ans,f[i][j]);
		}
	}
	printf("%lld",ans);
	return 0;
}
